text:
{relatedPosts.length > 0 && (
  <section class="border-t border-border py-[var(--space-section-sm)]">
    <h2 class="font-display text-2xl font-bold text-foreground mb-[var(--space-stack-lg)] text-center">
      Related Posts
    </h2>

    <div class="grid gap-[var(--space-stack-lg)] md:grid-cols-2 lg:grid-cols-3">
      {relatedPosts.map((post) => (
        <BlogCard
          title={post.data.title}
          description={post.data.description}
          href={getPostUrl(post.id)}
          publishedAt={post.data.publishedAt}
          tags={post.data.tags}
          author={post.data.author}
          image={post.data.image}
          svgSlug={post.data.svgSlug}
        />
      ))}
    </div>
  </section>
)}

{import.meta.env.PROD && (
<script is:inline define:vars={{ scriptUrl: url('/pagefind/pagefind.js') }}>
    if (!window.pagefind) {
        async function loadPagefind() {
            const url = scriptUrl.replace(/\/$/, "")
            try {
                const response = await fetch(url, { method: 'HEAD' });
                if (response.status !== 200) {
                    return;
                }
                const pagefind = await import(scriptUrl);
                await pagefind.options({
                    "excerptLength": 20
                });
                window.pagefind = pagefind;
                window.dispatchEvent(new Event('pagefindready'));
            } catch (error) {
                console.warn("Pagefind script not found or failed to load.");
                window.dispatchEvent(new Event('pagefindloaderror'));
            }
        }
        loadPagefind();
    }
</script>
)}

if (!isSupported) {
	return (
		<div className="rounded-lg border border-kumo-danger/50 bg-kumo-danger/10 p-4">
			<h3 className="font-medium text-kumo-danger">{t`Passkeys Not Available Here`}</h3>
			<p className="mt-1 text-sm text-kumo-subtle">
				{insecureContext ? (
					<>
						{t`Passkeys require a`}{" "}
						<strong className="text-kumo-default">{t`secure context`}</strong>
						{t`: use`} <strong className="text-kumo-default">HTTPS</strong>
						{t`, or open the admin at`}{" "}
						<strong className="text-kumo-default">http://localhost</strong>{" "}
						{t`(with your dev port).`}
						{t`Plain`} <code className="text-xs">http://</code>{" "}
						{t`on a custom hostname is not treated as secure, even on loopback.`}
					</>
				) : (
					<>
						{t`Your browser doesn't support passkeys. Please use a modern browser like Chrome, Safari, Firefox, or Edge.`}
					</>
				)}
			</p>
		</div>
	);
}

const DIFF_STYLES: Record<DiffKind, { bg: string; icon: React.ReactNode; label: string }> = {
	added: {
		bg: "bg-green-50 dark:bg-green-950/30 border-green-200 dark:border-green-800",
		icon: <Plus className="h-3 w-3 text-green-600 dark:text-green-400" aria-hidden="true" />,
		label: "Added",
	},
	removed: {
		bg: "bg-red-50 dark:bg-red-950/30 border-red-200 dark:border-red-800",
		icon: <Minus className="h-3 w-3 text-red-600 dark:text-red-400" aria-hidden="true" />,
		label: "Removed",
	},
	changed: {
		bg: "bg-amber-50 dark:bg-amber-950/30 border-amber-200 dark:border-amber-800",
		icon: (
			<PencilSimple className="h-3 w-3 text-amber-600 dark:text-amber-400" aria-hidden="true" />
		),
		label: "Changed",
	},
	unchanged: {
		bg: "bg-kumo-tint/50 border-kumo-line",
		icon: null,
		label: "Unchanged",
	},
};

return (
	<>
		<Button variant={variant} onClick={handleClick}>
			{element.label}
		</Button>
		{element.confirm && (
			<DialogRoot open={confirmOpen} onOpenChange={setConfirmOpen}>
				<Dialog>
					<h3 className="text-lg font-semibold text-kumo-default">{element.confirm.title}</h3>
					<p className="mt-1 text-sm text-kumo-subtle">{element.confirm.text}</p>
					<div className="flex justify-end gap-2 pt-4">
						<Button variant="secondary" onClick={() => setConfirmOpen(false)}>
							{element.confirm.deny}
						</Button>
						<Button
							variant={element.confirm.style === "danger" ? "destructive" : "primary"}
							onClick={handleConfirm}
						>
							{element.confirm.confirm}
						</Button>
					</div>
				</Dialog>
			</DialogRoot>
		)}
	</>
);

return (
	<div className="space-y-2">
		{submissions.map((sub) => {
			const preview = Object.values(sub.data)
				.filter((v) => typeof v === "string" && v.length > 0)
				.slice(0, 1)
				.map(String)
				.join("");

			return (
				<div key={sub.id} className="flex items-center justify-between text-xs">
					<div className="flex items-center gap-2 min-w-0">
						<Badge variant={sub.status === "new" ? "success" : "default"}>{sub.status}</Badge>
						<span className="truncate">{preview || formMap.get(sub.formId) || "Submission"}</span>
					</div>
					<span className="text-muted-foreground whitespace-nowrap ms-2">
						{formatDate(sub.createdAt)}
					</span>
				</div>
			);
		})}
	</div>
);

return (
	<div className="min-h-screen flex items-center justify-center bg-kumo-base p-4">
		<div className="w-full max-w-md">
			<div className="text-center mb-8">
				<LogoLockup className="h-10 mx-auto mb-2" />
				<h1 className="text-2xl font-semibold text-kumo-default">
					{step === "register" && t`Accept Invite`}
					{step === "error" && t`Invite Error`}
				</h1>
			</div>

			<div className="bg-kumo-base border rounded-lg shadow-sm p-6">
				{step === "register" && inviteData && token && (
					<RegisterStep inviteData={inviteData} token={token} />
				)}

				{step === "error" && (
					<ErrorStep message={error ?? t`An unknown error occurred`} code={errorCode} />
				)}
			</div>
		</div>
	</div>
);

const openSidebar = () => {
	const storage = (editor.storage as unknown as Record<string, Record<string, unknown>>).image;
	const onOpen = storage?.onOpenBlockSidebar as
		| ((panel: {
				type: "image";
				attrs: ImageAttributes;
				onUpdate: (attrs: Partial<ImageAttributes>) => void;
				onReplace: (attrs: ImageAttributes) => void;
				onDelete: () => void;
				onClose: () => void;
		  }) => void)
		| null;
	if (onOpen) {
		sidebarOpenRef.current = true;
		onOpen({
			type: "image",
			attrs: getImageAttrs(),
			onUpdate: (attrs: Partial<ImageAttributes>) => updateAttributes(attrs),
			onReplace: (attrs: ImageAttributes) => updateAttributes(attrs),
			onDelete: () => deleteNode(),
			onClose: () => {
				sidebarOpenRef.current = false;
			},
		});
	}
};

return (
	<div className={cn("flex items-center gap-1.5", className)}>
		<GlobeSimple
			className={cn("text-kumo-subtle shrink-0", size === "sm" ? "size-3.5" : "size-4")}
			weight="bold"
		/>
		<select
			value={value}
			onChange={(e) => onChange(e.target.value)}
			aria-label={t`Locale`}
			className={cn(
				"rounded-md border bg-transparent font-medium transition-colors",
				"focus:ring-kumo-ring focus:outline-none focus:ring-2 focus:ring-offset-1",
				"hover:bg-kumo-tint/50 cursor-pointer",
				size === "sm" ? "px-1.5 py-0.5 text-xs" : "px-2 py-1 text-sm",
			)}
		>
			{showAll && <option value="">{t`All locales`}</option>}
			{locales.map((locale) => (
				<option key={locale} value={locale}>
					{locale.toUpperCase()}
					{locale === defaultLocale ? t` (default)` : ""}
				</option>
			))}
		</select>
	</div>
);
